#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <iostream>
#include <omp.h>
#include <cstring>

using namespace std;

#define HALO     1
#define STR_SIZE 256
#define M_SEED   9

#define IN_RANGE(x, min, max) ((x)>= (min) && (x)<= (max))
#define CLAMP_RANGE(x, min, max) x = (x< (min)) ? min : ((x> (max)) ? max : x )
#define MIN(a, b) ((a)<= (b) ? (a) : (b))

int rows = -1, cols = -1;
int Ne = rows * cols;
int* data;
int** wall;
int* result;
int pyramid_height = -1;
int verbose = 0;

#ifdef TIMING
	struct timeval tv;
	struct timeval tv_total_start, tv_total_end;
	struct timeval tv_init_end;
	struct timeval tv_h2d_start, tv_h2d_end;
	struct timeval tv_d2h_start, tv_d2h_end;
	struct timeval tv_kernel_start, tv_kernel_end;
	struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
	struct timeval tv_close_start, tv_close_end;
	float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
		  d2h_time = 0, close_time = 0, total_time = 0;
#endif

void tvsub(struct timeval *t1, struct timeval *t2, struct timeval *r)
{
	r->tv_sec = t1->tv_sec - t2->tv_sec;
	r->tv_usec = t1->tv_usec - t2->tv_usec;
	if (r->tv_usec < 0) {
		r->tv_sec--;
		r->tv_usec += 1000000;
	}
}

void init(int argc, char** argv)
{
    int cur_arg;
	for (cur_arg = 1; cur_arg<argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-c") == 0) {
            if (argc >= cur_arg + 1) {
                cols = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-r") == 0) {
            if (argc >= cur_arg + 1) {
                rows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-h") == 0) {
            if (argc >= cur_arg + 1) {
                pyramid_height = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        if (strcmp(argv[cur_arg], "-v") == 0) {
			verbose = 1;
        }
    }

	if (cols < 0 || rows < 0 || pyramid_height < 0)
	{
        fprintf(stderr, "usage: %s <-r rows> <-c cols> <-h pyramid_height> [-v]\n", argv[0]);
		exit(0);
	}
	data = new int[rows * cols];
	wall = new int*[rows];
	for (int n = 0; n < rows; n++)
	{
		wall[n] = data + cols * n;
	}
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; i < rows; i++)
	{
		for (int j = 0; j < cols; j++)
		{
			wall[i][j] = rand() % 10;
		}
	}
#ifdef BENCH_PRINT
	for (int i = 0; i < rows; i++)
	{
		for (int j = 0; j < cols; j++)
		{
			printf("%d ", wall[i][j]);
		}
		printf("\n");
	}
#endif
}

void fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);
}

void dynproc_kernel(int iteration,
                    int* gpuWall,
                    int* gpuSrc,
                    int* gpuResults,
                    int cols,
                    int rows,
                    int startStep,
                    int border,
                    int HALO,
                    int* prev,
                    int* result_local,
                    int* outputBuffer,
                    int BLOCK_SIZE,
                    int bx,
                    int tx)
{
	int small_block_cols = BLOCK_SIZE - (iteration*HALO*2);

	int blkX = (small_block_cols*bx) - border;
	int blkXmax = blkX+BLOCK_SIZE-1;

	int xidx = blkX+tx;

	int validXmin = (blkX < 0) ? -blkX : 0;
	int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

	int W = tx-1;
	int E = tx+1;

	W = (W < validXmin) ? validXmin : W;
	E = (E > validXmax) ? validXmax : E;

	bool isValid = IN_RANGE(tx, validXmin, validXmax);

	if(IN_RANGE(xidx, 0, cols-1))
	{
		prev[tx] = gpuSrc[xidx];
	}

	#pragma omp barrier

	bool computed;
	for (int i = 0; i < iteration; i++)
	{
		computed = false;

		if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid )
		{
			computed = true;
			int left = prev[W];
			int up = prev[tx];
			int right = prev[E];
			int shortest = MIN(left, up);
			shortest = MIN(shortest, right);

			int index = cols*(startStep+i)+xidx;
			result_local[tx] = shortest + gpuWall[index];

			if (tx==11 && i==0)
			{
				int bufIndex = gpuSrc[xidx];
				outputBuffer[bufIndex] = 1;
			}

		}

		#pragma omp barrier

		if(i==iteration-1)
		{
			break;
		}

		if(computed)
		{
			prev[tx] = result_local[tx];
		}
		#pragma omp barrier;
	}

	if (computed)
	{
		gpuResults[xidx] = result_local[tx];
	}
}

int main(int argc, char** argv)
{
	init(argc, argv);

	int borderCols = (pyramid_height) * HALO;

	int size = rows * cols;

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef  TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    int* h_outputBuffer = (int*)malloc(16384 * sizeof(int));
    for (int i = 0; i < 16384; i++) {
        h_outputBuffer[i] = 0;
	}

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	int BLOCK_SIZE = 256;
	int num_blocks = (cols + BLOCK_SIZE - 1) / BLOCK_SIZE;

	int src = 1, final_ret = 0;

	int* d_gpuResult[2];
	d_gpuResult[0] = new int[cols];
	d_gpuResult[1] = new int[cols];

	for (int i = 0; i < cols; i++) {
		d_gpuResult[0][i] = data[i];
		d_gpuResult[1][i] = 0;
	}

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

	for (int t = 0; t < rows - 1; t += pyramid_height)
	{
		int temp = src;
		src = final_ret;
		final_ret = temp;

		int arg0 = MIN(pyramid_height, rows-t-1);
		int theHalo = HALO;

		int** prev_blocks = new int*[num_blocks];
		int** result_blocks = new int*[num_blocks];
		for (int b = 0; b < num_blocks; b++) {
			prev_blocks[b] = new int[BLOCK_SIZE];
			result_blocks[b] = new int[BLOCK_SIZE];
		}

		#pragma omp parallel num_threads(num_blocks * BLOCK_SIZE)
		{
			int thread_id = omp_get_thread_num();
			int bx = thread_id / BLOCK_SIZE;
			int tx = thread_id % BLOCK_SIZE;

			if (bx < num_blocks && tx < BLOCK_SIZE)
			{
				int* prev = prev_blocks[bx];
				int* result_local = result_blocks[bx];

				dynproc_kernel(arg0,
                               data + cols,
                               d_gpuResult[src],
                               d_gpuResult[final_ret],
                               cols,
                               rows,
                               t,
                               borderCols,
                               theHalo,
                               prev,
                               result_local,
                               h_outputBuffer,
                               BLOCK_SIZE,
                               bx,
                               tx);
			}
		}

		for (int b = 0; b < num_blocks; b++) {
			delete[] prev_blocks[b];
			delete[] result_blocks[b];
		}
		delete[] prev_blocks;
		delete[] result_blocks;
	}

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	for (int i = 0; i < cols; i++) {
		result[i] = d_gpuResult[final_ret][i];
	}

	h_outputBuffer[16383] = '\0';

#ifdef BENCH_PRINT
	for (int i = 0; i < cols; i++)
		printf("%d ", data[i]);
	printf("\n");
	for (int i = 0; i < cols; i++)
		printf("%d ", result[i]);
	printf("\n");
#endif

#ifdef  TIMING
	gettimeofday(&tv_close_start, NULL);
#endif

	delete[] d_gpuResult[0];
	delete[] d_gpuResult[1];
	delete[] data;
	delete[] wall;
	delete[] result;
	free(h_outputBuffer);

#ifdef  TIMING
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_start, &tv);
	close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    gettimeofday(&tv_total_end, NULL);
    tvsub(&tv_total_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

	return EXIT_SUCCESS;
}
